mapper.select:
SELECT id, product_id AS "productId", supplier_id AS "supplierId",
       offer_price AS "offerPrice", mrp, discount_percent AS "discountPercent",
       state_id AS "stateId", flow_id AS "flowId", created_time AS "createdAt"
FROM offer

  AND id = #{id}
  AND product_id = #{productId}
  AND supplier_id = #{supplierId}
  AND state_id = #{stateId}

ORDER BY created_time DESC

SELECT COUNT(*) FROM offer

  AND state_id = #{stateId}
  AND supplier_id = #{supplierId}
